case "in":
    inVals, _ := f.Value.([]interface{})
    if len(inVals) == 0 {
        conditions = append(conditions, "1 = 0")
        continue
    }
    if len(inVals) > MaxINListSize {
        return "", nil, fmt.Errorf("IN filter on field %q exceeds maximum of %d values", f.Field, MaxINListSize)
    }
    // ... rest unchanged
```

